    import unicodedata

    if type(x) is not str:
        return False
    if len(x) != 43:
        return False
    if any(ord(ch) < 128 for ch in x):
        return False

    s = unicodedata.normalize("NFKC", x)

    try:
        b = s.encode("ascii")
    except UnicodeEncodeError:
        return False

    if len(b) != 43:
        return False

