            return ((c - 65 + 13) % 26) + 65
        if 97 <= c <= 122:
            return ((c - 97 + 13) % 26) + 97
        return c

    b = bytes(r13(c) for c in b)

    return int.from_bytes(hashlib.sha256(b).digest(), "little") == (
